cssRules.rule:
@media (max-width: 767px) {
  [name="data-hover"] { margin: 0px; }
  [name="data-hover"] .box { width: 100%; }
  [name="data-hover"] .box .label-big { margin: 30px 0px 15px; height: auto !important; }
  [name="data-hover"] .box .image { margin-bottom: 15px; }
  [name="data-hover"] .box .image .hover { opacity: 1 !important; }
  [name="data-hover"] .box .hover-data { display: block !important; }
